UPDATE space_reservation
space_id = #{spaceId}, custom_space_name = #{customSpaceName}, reservation_date = #{reservationDate}, start_time = #{startTime}, end_time = #{endTime}, purpose = #{purpose}, attendee_count = #{attendeeCount}, contact_phone = #{contactPhone}, status = #{status}, approval_status = #{approvalStatus}, reviewer_id = #{reviewerId}, review_comment = #{reviewComment}, review_time = #{reviewTime}, update_time = NOW()
